mapper.select:
select count(*) from workplace where wp_usage = 'Y'
and wp_type = #{searchType}
and ( upper(wp_name) like trim(upper('%' || #{searchKeyword} || '%')) or upper(wp_id) like trim(upper('%' || #{searchKeyword} || '%')) )

SELECT * FROM ( SELECT ROWNUM RN, p.* FROM ( SELECT wp.wp_id as wpId, wp.wp_name as wpName, wp.wp_type as wpTypeNo, wt.wp_type_name as wpType, wp.wp_img as wpImg, ghp.ghp_id AS ghpId, ghp.GHP_NAME AS ghpName, wt.wp_type_content as wpTypeContent FROM workplace wp LEFT OUTER JOIN wp_type wt ON wp.wp_type = wt.wp_type_no LEFT OUTER JOIN ghp ghp ON wp.wp_id = ghp.GHP_WPID WHERE wp_usage = 'Y'
and wp_type = #{wpDTO.searchType}
and ( upper(wp_name) like trim(upper('%' || #{wpDTO.searchKeyword} || '%')) or upper(wp_id) like trim(upper('%' || #{wpDTO.searchKeyword} || '%')) )
ORDER BY wp_type_no, wp_id ) p ) WHERE RN BETWEEN #{page.startRow} AND #{page.endRow}
